proc get_url {url} {
    set token [::http::geturl $url]
    set body [::http::data $token]
    ::http::cleanup $token
    return $body
}

proc get_data {url} {
    set token [::http::geturl $url]
    set body [::http::data $token]
    ::http::cleanup $token
    set pattern {<body.*?>(.*?)</body>}
    set data ""
    regexp -nocase $pattern $body match data
    return $data
}
